    elems = list(string.ascii_uppercase[:8])
    def build(depth):
        if depth <= 0 or rng.random() < 0.4:
            e = rng.choice(elems)
            c = rng.randrange(1, 6)
            return e + (str(c) if c > 1 else '')
        parts = ''.join(build(depth - 1) for _ in range(rng.randrange(1, 3)))
        c = rng.randrange(1, 5)
        return '(' + parts + ')' + (str(c) if c > 1 else '')
    s = ''.join(build(3) for _ in range(rng.randrange(1, 4)))
    if not s:
        s = 'H'
    return [s[:1000]]

