class Solution:
    def countOfAtoms(self, formula):
        import re
        from collections import Counter
        i = 0
        n = len(formula)
        def parse():
            nonlocal i
            counts = Counter()
            while i < n and formula[i] != ')':
                if formula[i] == '(':
                    i += 1
                    inner = parse()
                    i += 1  # skip ')'
                    num = ''
                    while i < n and formula[i].isdigit():
                        num += formula[i]
                        i += 1
                    mult = int(num) if num else 1
                    for k, v in inner.items():
                        counts[k] += v * mult
                else:
                    name = formula[i]
                    i += 1
                    while i < n and formula[i].islower():
                        name += formula[i]
                        i += 1
                    num = ''
                    while i < n and formula[i].isdigit():
                        num += formula[i]
                        i += 1
                    counts[name] += int(num) if num else 1
            return counts
        result = parse()
        out = ''
        for name in sorted(result):
            out += name
            if result[name] > 1:
                out += str(result[name])
        return out

