class Solution:
    def countOfAtoms(self, formula):
        from collections import Counter
        stack = [Counter()]
        i = 0
        n = len(formula)
        while i < n:
            ch = formula[i]
            if ch == '(': 
                stack.append(Counter())
                i += 1
            elif ch == ')':
                i += 1
                num = ''
                while i < n and formula[i].isdigit():
                    num += formula[i]
                    i += 1
                mult = int(num) if num else 1
                top = stack.pop()
                for k, v in top.items():
                    stack[-1][k] += v * mult
            else:
                name = ch
                i += 1
                while i < n and formula[i].islower():
                    name += formula[i]
                    i += 1
                num = ''
                while i < n and formula[i].isdigit():
                    num += formula[i]
                    i += 1
                stack[-1][name] += int(num) if num else 1
        result = stack[0]
        out = []
        for name in sorted(result):
            out.append(name)
            if result[name] > 1:
                out.append(str(result[name]))
        return ''.join(out)

