var countOfAtoms = function(formula) {
    const stack = [new Map()];
    let i = 0;
    const n = formula.length;
    const isDigit = c => c >= '0' && c <= '9';
    const isLower = c => c >= 'a' && c <= 'z';
    const isUpper = c => c >= 'A' && c <= 'Z';
    const add = (m, k, v) => m.set(k, (m.get(k) || 0) + v);
    while (i < n) {
        const ch = formula[i];
        if (ch === '(') {
            stack.push(new Map());
            i++;
        } else if (ch === ')') {
            i++;
            let num = '';
            while (i < n && isDigit(formula[i])) num += formula[i++];
            const mult = num ? parseInt(num, 10) : 1;
            const top = stack.pop();
            const parent = stack[stack.length - 1];
            for (const [k, v] of top) add(parent, k, v * mult);
        } else {
            let name = ch;
            i++;
            while (i < n && isLower(formula[i])) name += formula[i++];
            let num = '';
            while (i < n && isDigit(formula[i])) num += formula[i++];
            add(stack[stack.length - 1], name, num ? parseInt(num, 10) : 1);
        }
    }
    const result = stack[0];
    const names = [...result.keys()].sort();
    let out = '';
    for (const name of names) {
        out += name;
        if (result.get(name) > 1) out += result.get(name);
    }
    return out;
};
